By the way, I'm trying to do something different...i know, it's tricky, but it's working (this snippet will slightly slow the print process), basically, the inherited class (EscposIO), redefines the constructor method and the writelines method.
The writelines methods: every two lines will close the socket, wait 100ms and tries to reopen it; if something will fail, the exception will be catched and using a recursive call to the same method the lines queue will be consumed.

All suggestions are welcome!


```

from queue import Queue
from escpos.escpos import EscposIO, six
import time


class CustomEscPosIO(EscposIO):
	def __init__(self, printer, autocut=True, autoclose=False, **kwargs):

		self.text_queue = Queue()
		super(CustomEscPosIO, self).__init__(printer=printer, autocut=autocut, autoclose=autoclose, **kwargs)

	def writelines(self, text, reprint_exception=False, check_alive=True, **kwargs):

		try:
			params = dict(self.params)
			params.update(kwargs)

			if isinstance(text, six.text_type):
				lines = text.split('\n')
			elif isinstance(text, list) or isinstance(text, tuple):
				lines = text
			else:
				lines = ["{0}".format(text), ]

			#If the chesk alive it's enabled and the reprint_exception flag is false
			if check_alive and not reprint_exception:
				self.text_queue.put({'text': lines, 'params': params})
			#Close and reopen the connection, checking if the device it's still online
			for line in lines:
				if self.text_queue.qsize() % 2 == 0:
					self.printer.close()
					time.sleep(0.1)
					self.printer.open()
					params.update(kwargs)

				self.printer.set(**params)
				if isinstance(text, six.text_type):
					self.printer.text(u"{0}\n".format(line))
				else:
					self.printer.text("{0}\n".format(line))
		except Exception as ex:
			self.printer.close()
			time.sleep(5)
			self.printer.open()

			#Tries to flush the queue, reprinting everything
			while not self.text_queue.empty():
				data = self.text_queue.get()
				self.writelines(data['text'], reprint_exception=True, **data['params'])



```

